use std::pin::Pin;
use std::future::Future;

// Returning different async types requires boxing
fn get_task(fast: bool) -> Pin<Box<dyn Future<Output = String> + Send>> {
    if fast {
        Box::pin(async { "fast result".to_string() })
    } else {
        Box::pin(async {
            tokio::time::sleep(tokio::time::Duration::from_secs(1)).await;
            "slow result".to_string()
        })
    }
}

use tokio::sync::Mutex;
use std::sync::Arc;

async fn bad_example(data: Arc<Mutex<Vec<String>>>) {
    // BAD: MutexGuard held across await point
    // let mut lock = data.lock().await;
    // some_async_operation().await;  // Lock is still held!
    // lock.push("item".into());

    // GOOD: Drop the lock before awaiting
    {
        let mut lock = data.lock().await;
        lock.push("item".into());
    }  // Lock dropped here
    some_async_operation().await;  // Safe!
}

async fn some_async_operation() {}

// BAD: blocks the async runtime thread
async fn bad_cpu_work() -> u64 {
    // std::thread::sleep(Duration::from_secs(5)); // NEVER do this!
    // expensive_computation();  // Blocks other tasks!
    0
}

// GOOD: use spawn_blocking for CPU-heavy work
async fn good_cpu_work() -> u64 {
    tokio::task::spawn_blocking(|| {
        // This runs on a dedicated thread pool
        expensive_computation()
    })
    .await
    .unwrap()
}

fn expensive_computation() -> u64 {
    (0..1_000_000u64).sum()
}

use std::rc::Rc;  // Rc is NOT Send!

// This will NOT compile with tokio::spawn:
// tokio::spawn(async {
//     let data = Rc::new(42);  // Rc is not Send
//     some_await_point().await;
//     println!("{}", data);
// });

// Fix: use Arc instead of Rc
use std::sync::Arc;

async fn works() {
    tokio::spawn(async {
        let data = Arc::new(42);  // Arc IS Send
        tokio::time::sleep(tokio::time::Duration::from_millis(1)).await;
        println!("{}", data);
    });
}
